query:
SELECT table_name 
FROM information_schema.tables 
WHERE table_schema = 'public';

SELECT * 
FROM ministries 
WHERE name = 'Министерство финансов';

SELECT * 
FROM ministries 
WHERE employees_count > 1000;

SELECT * 
FROM periods 
WHERE year BETWEEN 2020 AND 2025;

SELECT * 
FROM expense_items 
WHERE name IN ('Зарплаты', 'Инфраструктура');

SELECT * 
FROM expense_items 
WHERE name LIKE 'Соц%';

SELECT * 
FROM ministries 
ORDER BY name;

SELECT * 
FROM ministries 
ORDER BY employees_count DESC;

SELECT * 
FROM ministries 
ORDER BY name, employees_count;

SELECT * 
FROM ministry_budget_view 
ORDER BY ministry_name, year, month;

SELECT * 
FROM ministry_statistics 
ORDER BY "Средние расходы" DESC NULLS LAST;
